class Solution:
    def countGoodStrings(self, low, high, zero, one):
        MOD = 10**9 + 7
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(300000)
        @lru_cache(maxsize=None)
        def ways(length):
            if length > high:
                return 0
            total = 1 if length >= low else 0
            total += ways(length + zero)
            total += ways(length + one)
            return total % MOD
        return ways(0) % MOD

