class Solution:
    def countGoodStrings(self, low, high, zero, one):
        MOD = 10**9 + 7
        f = [0] * (high + 1)
        f[0] = 1
        ans = 0
        for i in range(1, high + 1):
            if i >= zero:
                f[i] = (f[i] + f[i - zero]) % MOD
            if i >= one:
                f[i] = (f[i] + f[i - one]) % MOD
            if i >= low:
                ans = (ans + f[i]) % MOD
        return ans

